INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$79032b26-a604-4dff-ad27-30f0060ae5a6$tag$, $tag$2026022300153$tag$, $tag$Gabriel Glicério (5583987549518)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"23/02/2026 14:39:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá","time":"23/02/2026 14:47:32"},{"role":"agent","text":"*Karina Pimentel:* Tudo bem?\n😊 Sou a Karina do departamento de Relacionamento Comercial da Faculdade Internacional Cidade Viva!\nIdentificamos o seu interesse pelos nossos cursos, vou lhe enviar maiores informações! Me confirme o curso por gentileza!","time":"23/02/2026 16:27:27","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bacharelado em tecnologia Ead","time":"23/02/2026 16:29:42"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"24/02/2026 13:39:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"24/02/2026 13:40:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"É aceito nota do Enem?","time":"24/02/2026 13:42:49"},{"role":"client","text":"Existe possibilidade de bolsa?","time":"24/02/2026 13:43:03"},{"role":"client","text":"Conheço pouco sobre a faculdade cidade viva","time":"24/02/2026 13:43:21"},{"role":"agent","text":"*Karina Pimentel:* Dos últimos 5 anos, Nota menina de 450.","time":"24/02/2026 13:56:57","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Não. Somente requerimento para solicitar descontos! ","time":"24/02/2026 13:57:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* https://ficv.edu.br/cursos/ead","time":"24/02/2026 13:57:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nGabriel Glicério, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"25/02/2026 18:09:33"}]$tag$, $tag$2026-02-23 14:39:30+00$tag$, FALSE, FALSE, 7.4, $tag$2026-03-01 16:42:01.563441+00$tag$, 7, 10, 9, 2, 9, 7, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$b6005b34-a159-4658-a29b-a48cd633522b$tag$, $tag$2026022300154$tag$, $tag$Bruno Silva (5519996969044)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página lideranca Crista e quero mais informações.","time":"23/02/2026 14:39:42"},{"role":"client","text":"🌟 Boa tarde Bruno Silva! Que alegria ter você aqui com a gente! 🙌","time":"23/02/2026 14:39:43"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/02/2026 14:39:47"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/02/2026 14:39:51"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"23/02/2026 14:39:55"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"23/02/2026 14:40:01"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"23/02/2026 14:40:07"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"23/02/2026 14:40:08"},{"role":"client","text":"Sim, concordo","time":"23/02/2026 14:40:23"},{"role":"client","text":"✅ Obrigado, Bruno Silva! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"23/02/2026 14:40:24"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/02/2026 14:40:28"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/02/2026 14:40:43"},{"role":"client","text":"Olá! Bruno Silva!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/02/2026 14:40:44"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/02/2026 14:40:48"},{"role":"client","text":"Saber sobre os cursos","time":"23/02/2026 14:41:01"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/02/2026 14:41:05"},{"role":"client","text":"Pós-Graduação","time":"23/02/2026 14:41:13"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/02/2026 14:41:18"},{"role":"client","text":"Liderança Cristã","time":"23/02/2026 14:41:36"},{"role":"client","text":"Lidere com sabedoria, integridade e propósito.\n 🧭 Curso voltado para líderes de igrejas, ministérios e organizações cristãs\n 🌍 Temas como discipulado, liderança servidora e gestão de equipes\n 📅 Ainda dá tempo de começar este semestre!\n","time":"23/02/2026 14:41:38"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/02/2026 14:41:41"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/02/2026 14:41:51"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/02/2026 14:41:51"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/02/2026 14:53:19"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"23/02/2026 14:53:49","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:*  *Pós-graduação em Liderança Cristã*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO E CARGA HORÁRIA\nO curso tem duração de 16 meses, com carga horária de 400h.\n\nDISCIPLINAS\nContamos com um total de 10 disciplinas.\n\nAULAS E AVALIAÇÕES\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas. As avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigatoriedade de TCC.","time":"23/02/2026 14:54:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  *Liderança Cristã* - Disciplinas do Curso:\n\n*A Vida e a Cosmovisão do Líder*\nCosmovisão Cristã\nA espiritualidade do Líder\n\n*A Igreja, seus propósitos e a Sua missão*\nOs propósitos da Igreja I\nOs propósitos da Igreja II\n\n*Liderança Missional e prática ministerial*\nTeologia Bíblica da Liderança\nLiderança Eclesiástica\nTeologia e Prática da Pregação Expositiva\nGestão Eclesiástica\nPlantação de Igrejas Missionais\n\n*Igrejas que transformam o Brasil*\nIgrejas que transformam o Brasil\nMódulo Optativo - ITB Aplicado (Parceria Rede Godstock)\n\nObs: Professores sujeitos a alterações.","time":"23/02/2026 14:54:08","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Liderança Cristã está em 16 mensalidades de *R$ 359,37*.  \n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"23/02/2026 14:54:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Está com uma uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas  R$ 179,68\n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"23/02/2026 14:54:30","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"24/02/2026 08:14:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nBruno Silva, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"24/02/2026 14:54:18"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"24/02/2026 14:54:20"},{"role":"client","text":"Bruno Silva, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"24/02/2026 15:09:20"}]$tag$, $tag$2026-02-23 14:39:42+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$98ba252d-98ce-41d7-81db-a2e2098c7aa6$tag$, $tag$2026022400038$tag$, $tag$2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento (5585986596768)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"24/02/2026 08:24:02"},{"role":"client","text":"🌟 Bom dia 2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento! Que alegria ter você aqui com a gente! 🙌","time":"24/02/2026 08:24:03"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"24/02/2026 08:24:07"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"24/02/2026 08:24:11"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"24/02/2026 08:24:18"},{"role":"client","text":"Faculdade","time":"24/02/2026 08:24:23"},{"role":"client","text":"Olá! 2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"24/02/2026 08:24:24"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"24/02/2026 08:24:27"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"24/02/2026 08:24:28"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"24/02/2026 08:24:28"},{"role":"client","text":"Falar com um atendente","time":"24/02/2026 08:24:43"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"24/02/2026 08:24:44"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"24/02/2026 08:25:35"},{"role":"client","text":"Bom dia \nFiz a inscrição com o desconto de 50% para todo o curso, porém ao baixar o app que foi informado via e-mail verifiquei que as parcelas estavam com o valar total.","time":"24/02/2026 08:26:00"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/699d8af494f5bdf2a90b156a)","time":"24/02/2026 08:26:44"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"24/02/2026 08:29:31","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Nome completo por gentileza!","time":"24/02/2026 08:29:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Alisson Naftali Carvalho do Nascimento","time":"24/02/2026 08:30:05"},{"role":"agent","text":"*Karina Pimentel:* Psicoteologia correto?","time":"24/02/2026 08:32:33","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Exato","time":"24/02/2026 08:32:46"},{"role":"agent","text":"*Karina Pimentel:* O senhor foi até o final, inscrição finalizada ok?","time":"24/02/2026 08:33:55","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Sim, realizei o pagamento e tudo mais.","time":"24/02/2026 08:34:20"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/699d8d77bbbe596dca054716)","time":"24/02/2026 08:37:27","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Prezados(as) alunos(as),\n\nSejam muito bem-vindos(as) à Pós-graduação em Psicoteologia EAD da Faculdade Internacional Cidade Viva!\n\nTemos a alegria de informar que o início oficial das aulas ocorrerá no dia 30 de março de 2026, com a liberação da primeira disciplina, Introdução à Psicoteologia, ministrada pelo Prof. Dr. Sérgio Queiroz.\n \nO acesso ao Ambiente Virtual de Aprendizagem (Moodle) será disponibilizado na semana que antecede o início do curso, e as orientações de acesso serão encaminhadas para o e-mail informado no ato da matrícula.\n \nEm relação às parcelas financeiras, os boletos serão enviados também por e-mail a partir do dia 30/03/2026.\n \nCaso necessitem de suporte ou tenham qualquer dúvida, nossa equipe está à disposição através dos seguintes contatos oficiais:\n\n- WhatsApp: (83) 3041-7471\n- E-mail: faculdade@cidadeviva.org\n📩 Obs: Os avisos e comunicados oficiais serão sempre enviados por e-mail, não mais por este grupo. \n\nDesejamos uma excelente jornada acadêmica e que este período seja de muito aprendizado e crescimento.\n\nDeus os abençoe!\n\nAtenciosamente,\n\nSecretaria Acadêmica\nFaculdade Internacional Cidade Viva","time":"24/02/2026 08:40:00","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Hoje será enviado esse comunicado aos alunos!","time":"24/02/2026 08:40:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok, já recebi. Mas não é sobre isso meu problema, é sobre o valor cobrado. \nNão foi isso que contratei, eu fiz o cadastro para 50% de desconto.","time":"24/02/2026 08:41:28"},{"role":"agent","text":"*Karina Pimentel:* Sim!","time":"24/02/2026 08:57:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* A sua 1 mensalidade pagou com desconto correto?","time":"24/02/2026 08:57:54","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Próximo boleto a ser pago será somente em Abril! Tendo em vista que começará em 30/03.","time":"24/02/2026 08:59:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"*Karina*:\nEstamos com uma oferta especial essa semana, 50% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 243,50.\nVamos garantir a sua vaga? 😊","time":"24/02/2026 09:01:28"},{"role":"client","text":"Não Karina, fiz o pagamento para pagar todas as parcelas com 50% de desconto","time":"24/02/2026 09:01:52"},{"role":"agent","text":"*Karina Pimentel:* Sim.","time":"24/02/2026 09:11:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/699d95a4334572cf380a6f0b)","time":"24/02/2026 09:12:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok, fico grato. Ainda bem hahaha","time":"24/02/2026 09:16:37"},{"role":"client","text":"Karina Pimentel transferiu o atendimento para a equipe FICV - SECRETARIA","time":"24/02/2026 15:26:41"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Abel Alves","time":"24/02/2026 15:27:59"},{"role":"client","text":"*Abel Alves:* Caro aluno, bom dia. ","time":"24/02/2026 15:28:11"},{"role":"client","text":"*Abel Alves:* Qual o seu nome completo ?","time":"24/02/2026 15:28:15"},{"role":"client","text":"Oi Abel \nKarina transferiu pra você correto?","time":"24/02/2026 15:51:49"},{"role":"client","text":"Alisson Naftali Carvalho do Nascimento","time":"24/02/2026 15:51:58"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/699ef25779ff2e18a102a171)","time":"25/02/2026 10:00:07"},{"role":"client","text":"Abel Alves transferiu o atendimento para a equipe FICV - COMERCIAL","time":"25/02/2026 10:00:20"},{"role":"client","text":"Obrigado","time":"25/02/2026 10:02:17"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"25/02/2026 10:21:19"},{"role":"client","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nFicou mais alguma dúvida?","time":"25/02/2026 10:21:41"},{"role":"client","text":"Queria só confirmar as informações: \n- Devido a postergação do início das aula o boleto da parcela fica para Abril, 10/4? \n- ⁠Revisão dos valores das parcelas com o desconto de 50% adquirido durante o período que foi oferecido pela instituição? (No app, aparece o valor integral, mas fiz o contrato de adesão com o cupom de desconto para todas as parcelas).","time":"25/02/2026 10:29:08"},{"role":"client","text":"*Thayanne Sales:* 1ª: Sim\n\n\n2ª: O valor da mensalidade vai cheio, Tem um aviso em verde e amarelo informando o desconto e  assim que prosseguir para área de pagamento o desconto aparece.","time":"25/02/2026 10:30:18"},{"role":"client","text":"Ok; obrigado","time":"25/02/2026 10:31:05"},{"role":"client","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"25/02/2026 10:32:25"},{"role":"client","text":"Tenho sim. \nQual o tempo mínimo da formação e qual o prazo máximo pra pós?","time":"25/02/2026 10:33:27"},{"role":"client","text":"*Thayanne Sales:* São no mínimo 16 meses e podendo ter um acréscimo de mais 6 meses ","time":"25/02/2026 10:36:07"},{"role":"client","text":"No caso então, eu “devo” a instituição quantas parcelas? As 16?","time":"25/02/2026 10:36:41"},{"role":"client","text":"*Thayanne Sales:* No caso como você está inscrito, já efetuou o pagamento da 1ª mensalidade","time":"25/02/2026 10:37:51"},{"role":"client","text":"Com isso você quer dizer que são 15?","time":"25/02/2026 10:47:41"},{"role":"client","text":"*Thayanne Sales:* Sim","time":"25/02/2026 11:09:29"},{"role":"client","text":"*Thayanne Sales:* Caso você precise de mais tempo de conclusão, ai só nesse caso terá que  pagar os meses a mais que precisar. ","time":"25/02/2026 11:10:25"},{"role":"client","text":"Ok","time":"25/02/2026 11:34:40"},{"role":"client","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"25/02/2026 11:35:05"},{"role":"client","text":"Não, muito obrigado e perdão pelas inúmeras perguntas!","time":"25/02/2026 12:01:56"},{"role":"client","text":"*Thayanne Sales:* Sem problemas, pode ficar a vontade para perguntar. ","time":"25/02/2026 13:16:26"},{"role":"client","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. ","time":"25/02/2026 13:16:32"},{"role":"client","text":"Atendimento Finalizado!\n\n2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"25/02/2026 13:16:37"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"25/02/2026 13:16:38"},{"role":"client","text":"2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"25/02/2026 13:31:38"}]$tag$, $tag$2026-02-24 08:24:02+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 25, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.ha