INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0ee1bdf6-15f8-4a1f-ab81-f86432d40407$tag$, $tag$2026022400040$tag$, $tag$Ingrid Germany (5583996255166)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"24/02/2026 08:29:46"},{"role":"client","text":"🌟 Bom dia Ingrid Germany! Que alegria ter você aqui com a gente! 🙌","time":"24/02/2026 08:29:47"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"24/02/2026 08:29:51"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"24/02/2026 08:29:54"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"24/02/2026 08:29:58"},{"role":"client","text":"Gostaria de saber valor mensal do curso e também a respeito do estágio, se é realizado na própria Cidade Viva.","time":"24/02/2026 08:29:59"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"24/02/2026 08:30:00"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"24/02/2026 08:30:04"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"24/02/2026 08:30:10"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"24/02/2026 08:30:10"},{"role":"client","text":"Sim, concordo","time":"24/02/2026 08:30:49"},{"role":"client","text":"✅ Obrigado, Ingrid Germany! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"24/02/2026 08:30:50"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"24/02/2026 08:30:54"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"24/02/2026 08:31:18"},{"role":"client","text":"Olá! Ingrid Germany!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"24/02/2026 08:31:19"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"24/02/2026 08:31:22"},{"role":"client","text":"Saber sobre os cursos","time":"24/02/2026 08:31:41"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"24/02/2026 08:31:45"},{"role":"client","text":"Graduação","time":"24/02/2026 08:32:03"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"24/02/2026 08:32:08"},{"role":"client","text":"Teologia (EAD)","time":"24/02/2026 08:32:37"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"24/02/2026 08:32:37"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"24/02/2026 08:32:41"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"24/02/2026 08:33:30"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"24/02/2026 08:33:31"},{"role":"client","text":"Gostaria de saber valor mensal do curso e também a respeito do estágio, se é realizado na própria Cidade Viva.","time":"24/02/2026 08:33:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"24/02/2026 08:49:05"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"24/02/2026 08:50:08","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"24/02/2026 08:50:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Muito obrigada pelas informações","time":"24/02/2026 08:52:31"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"24/02/2026 15:24:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Ficou alguma duvida?","time":"24/02/2026 15:24:21","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição?😊","time":"24/02/2026 15:24:37","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Agora não. Queria só saber informações primeiro. Obrigada.","time":"24/02/2026 16:21:56"},{"role":"client","text":"Atendimento Finalizado!\n\nIngrid Germany, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"25/02/2026 18:12:24"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"25/02/2026 18:12:25"},{"role":"client","text":"Ingrid Germany, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"25/02/2026 18:27:26"}]$tag$, $tag$2026-02-24 08:29:46+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 5, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
