INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c1f8ae05-1b3e-41b8-a8f1-ab9ba414ca17$tag$, $tag$2026022300171$tag$, $tag$Solange BeltrÃ£o (5583999343505)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"23/02/2026 15:19:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia","time":"24/02/2026 08:21:55"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!\nTudo bem?\n😊 Sou a Karina do departamento de Relacionamento Comercial da Faculdade Internacional Cidade Viva!\nIdentificamos o seu interesse pelos nossos cursos, vou lhe enviar maiores informações!\nMe confirme o curso por gentileza!","time":"24/02/2026 09:16:34","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Tenho graduação em bacharelado em Teologia no Betel Brasileiro e quero fazer uma especialização na área de capelania.","time":"24/02/2026 09:45:42"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"24/02/2026 09:50:03","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* PÓS GRADUAÇÕES: Liderança Cristã, Educação Cristã Clássica, Novo Testamento, Teologia Sistemática, Missiologia Urbana, Ciência Politica e Atuação Pública, Gestão Escolar, Psicopedagogia e Psicoteologia.","time":"24/02/2026 09:50:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Qual valor da pós graduação?","time":"24/02/2026 15:16:21"},{"role":"agent","text":"*Karina Pimentel:* Qual delas por gentileza?","time":"24/02/2026 18:12:40","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Ciência Política","time":"24/02/2026 21:41:26"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!\n\n*Pós-Graduação em Formação Política e Atuação Pública*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\nNossa carga horária é de 480 h.\n\nDISCIPLINAS\nContamos com um total de 11 disciplinas.\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n\nFormação Política e Atuação Pública - DISCIPLINAS DO CURSO:\n\nBASE: COSMOVISÃO CRISTÃ\nCosmovisão Cristã e Política \nIdeologias Políticas Contemporâneas\nÉtica Cristã \n\nBASE: CIÊNCIA POLÍTICA\nTeorias políticas clássicas\nTeoria política reformacional\nPolítica e Ordem Jurídica \nCidadania e Ação Cívica \n\nBASE: ATUAÇÃO PÚBLICA\nPoder Executivo \nPoder Legislativo\nPoder Judiciário \n\nDISCIPLINA FACULTATIVA\nMentoria para Candidatos a Mandatos Eletivos - Marketing e Posicionamento\n\nObs: Professores sujeitos a alterações.\n\nO valor de investimento na Pós-graduação em Formação Política e Atuação Pública  está em 16 mensalidades de *R$ 487,00*. Está com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 243,50.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Março/2026.\n","time":"25/02/2026 07:56:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nSolange BeltrÃ£o, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"26/02/2026 09:57:09"}]$tag$, $tag$2026-02-23 15:19:08+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 9, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2ef96aec-1cce-4387-b778-9b91d34d8215$tag$, $tag$2026022300172$tag$, $tag$Larissa Lopes (5588992428517)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página e quero mais informações.","time":"23/02/2026 15:19:55"},{"role":"client","text":"🌟 Boa tarde Larissa Lopes! Que alegria ter você aqui com a gente! 🙌","time":"23/02/2026 15:19:56"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/02/2026 15:20:00"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/02/2026 15:20:04"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"23/02/2026 15:20:08"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"23/02/2026 15:20:13"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"23/02/2026 15:20:19"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"23/02/2026 15:20:20"},{"role":"client","text":"Sim, concordo","time":"23/02/2026 15:22:47"},{"role":"client","text":"✅ Obrigado, Larissa Lopes! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"23/02/2026 15:22:48"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/02/2026 15:22:52"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/02/2026 15:23:06"},{"role":"client","text":"Olá! Larissa Lopes!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/02/2026 15:23:07"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/02/2026 15:23:11"},{"role":"client","text":"Saber sobre os cursos","time":"23/02/2026 15:23:53"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/02/2026 15:23:57"},{"role":"client","text":"Pós-Graduação","time":"23/02/2026 15:24:08"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/02/2026 15:24:12"},{"role":"client","text":"Psicopedagogia","time":"23/02/2026 15:24:30"},{"role":"client","text":"Essa pós é ideal para quem deseja compreender e intervir nos processos de aprendizagem com uma abordagem ética, cristã e prática.\n\n 🧠 100% online, estude no seu ritmo\n 🎓 Professores experientes e materiais atualizados\n 📅 Aulas iniciam em agosto\n 💰 Condição promocional especial para novas matrículas","time":"23/02/2026 15:24:31"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/02/2026 15:24:35"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/02/2026 15:24:53"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/02/2026 15:24:54"},{"role":"client","text":"Ok","time":"23/02/2026 15:25:20"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/02/2026 15:26:25"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"23/02/2026 15:26:38","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"23/02/2026 15:27:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Disciplinas da Pós em Psicopedagogia*\n\nBASE: FILOSÓFICA TEOLÓGICA\n\n1-Introdução à Cosmovisão Cristã - Dr. Bruno Ribeiro\n2-Fundamentos Filosóficos e Metodológicos de uma Pedagogia Cristã - Me. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Me. Thiago Dutra\n\nBASE: PSICOPEDAGOGIA E DESENVOLVIMENTO\n\n4-Fundamentos da Psicopedagogia - Ma. Luciana Siqueira\n5-Alfabetização Fônica - Esp. Finlândia de Oliveira das Chagas\n6-Aprendizagem da Matemática - Esp. Úrsula Keyla\n7-Desenvolvimento Cognitivo e Neurociência - Alessandra Schneider\n8-Síndromes, Transtornos e Dificuldades de Aprendizagem - Ma. Fabiana Josefa Sousa\n\nBASE: Avaliação, Diagnóstico e Mediação Psicopedagógica\n\n9-Teoria da Experiência de Aprendizagem Mediada em Feuerstein - Me. David Sasson/ Marcia Macionk\n10-Avaliação e Intervenção Psicopedagógica - Dra. Edith Rubstein\n11-Âmbitos de atuação do Psicopedagogo e Educação Formal - Esp. Karine Canani\n12-Temas contemporâneos em psicopedagogia:\n1- Inclusão e atuação do Psicopedagogo - Dra. Cristiane Souza;\n2- Uso das tecnologias e asimplicações para aprendizagem - Esp. Letícia Ruiz\n3- Altas Habilidades e Superdotação - Vera Pereira\n4- Direito Educacional Aplicado - Esp. Vladimir Miná\n5- Disciplina baseada em Virtudes -  Esp. LetíciaRuiz\n\n13 Seminário de práticas Psicopedagógicas - Ma. Fabiana Josefa Sousa/ Ma. Luciana Siqueira","time":"23/02/2026 15:27:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Psicopedagogia  está em 18 mensalidades de *R$ 479,16*.\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"23/02/2026 15:27:34","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Essa semana está com uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58.\n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"23/02/2026 15:27:48","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Olá, Thayanne!","time":"23/02/2026 15:29:39"},{"role":"client","text":"Agradeço pelas informações","time":"23/02/2026 15:29:47"},{"role":"client","text":"Tenho algumas dúvidas sobre o curso","time":"23/02/2026 15:30:30"},{"role":"client","text":"Essa pós me habilitaria a lecionar nessa área?","time":"23/02/2026 15:30:47"},{"role":"agent","text":"*Thayanne Sales:* Sim","time":"23/02/2026 15:32:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok. Eu estou para concluir uma pós nesse ano. No caso, meu intuito é iniciar outra pós em janeiro/2027.","time":"23/02/2026 15:35:34"},{"role":"client","text":"Fiquei bem interessada nessa de psicopedagogia","time":"23/02/2026 15:35:57"},{"role":"client","text":"Haverá turmas sendo iniciadas em janeiro? E quanto ao valor, há expectativa de se manter o valor promocional?","time":"23/02/2026 15:36:35"},{"role":"agent","text":"*Thayanne Sales:* Liberamos 2x ao ano turmas, mas o desconto delas são diferentes ","time":"23/02/2026 15:36:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Não é divulgado com tanta antecedência ","time":"23/02/2026 15:37:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Em períodos específicos do ano?","time":"23/02/2026 15:37:20"},{"role":"agent","text":"*Thayanne Sales:* Só quando abrimos a turma ","time":"23/02/2026 15:37:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"23/02/2026 15:37:45"},{"role":"agent","text":"*Thayanne Sales:* Esse ano liberamos as aulas para inicio em abril e outra em Outubro ","time":"23/02/2026 15:37:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obrigada pelo atendimento","time":"23/02/2026 15:37:54"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"23/02/2026 15:38:04","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Entendi. No caso, em outubro/26 será iniciada outra turma, certo?","time":"23/02/2026 15:38:38"},{"role":"agent","text":"*Thayanne Sales:* sim","time":"23/02/2026 15:39:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Mas a campanha de desconto varia mês a mês ","time":"23/02/2026 15:39:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Está bem, muito obrigada","time":"23/02/2026 15:47:04"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"23/02/2026 15:51:05","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não, obrigada!","time":"23/02/2026 15:52:21"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. ","time":"23/02/2026 16:32:27","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nLarissa Lopes, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/02/2026 16:32:48"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"23/02/2026 16:32:48"},{"role":"client","text":"5","time":"23/02/2026 16:40:47"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"23/02/2026 16:40:48"},{"role":"client","text":"Larissa Lopes, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"23/02/2026 16:55:49"}]$tag$, $tag$2026-02-23 15:19:55+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 15, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$80372af3-154f-4825-94fa-e255b00645f0$tag$, $tag$2026022300173$tag$, $tag$Rute Reis (5571991236543)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"23/02/2026 15:26:57"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"23/02/2026 15:26:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/02/2026 15:38:15"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"23/02/2026 15:38:32","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"23/02/2026 15:38:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"23/02/2026 15:38:45","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"23/02/2026 15:38:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"23/02/2026 15:38:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"24/02/2026 08:14:30","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sim","time":"24/02/2026 08:49:56"},{"role":"client","text":"Já realizei o pagamento e enviei a dissertação","time":"24/02/2026 08:50:12"},{"role":"agent","text":"*Thayanne Sales:* Que maravilha ","time":"24/02/2026 09:17:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"24/02/2026 09:18:03","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Os acessos para iniciar as aulas, recebo por e-mail?","time":"24/02/2026 09:22:17"},{"role":"agent","text":"*Thayanne Sales:* Sim, em 24h após a compensação do pagamento ","time":"24/02/2026 09:24:40","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Certo","time":"24/02/2026 09:31:46"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"24/02/2026 09:33:28","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não","time":"24/02/2026 09:33:53"},{"role":"client","text":"Obrigada","time":"24/02/2026 09:33:56"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia.","time":"24/02/2026 09:36:43","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nRute Reis, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"24/02/2026 09:36:51"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"27/02/2026 09:32:05"},{"role":"client","text":"Sua sessão expirou!","time":"27/02/2026 09:34:06"}]$tag$, $tag$2026-02-23 15:26:57+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 11, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5b405a10-5f5d-4c5a-aaef-3a9102dc54b2$tag$, $tag$2026022300174$tag$, $tag$Elizabeth Brito (5585984088831)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"23/02/2026 15:26:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Eu entrei em contato pra saber sobre o desconto da Consciência Cristã para pós","time":"23/02/2026 15:30:38"},{"role":"client","text":"Essa promoção ainda tá valendo?","time":"23/02/2026 15:30:52"},{"role":"client","text":"Eu fui a Consciência, mas não vi stand do seminário dessa vez","time":"23/02/2026 15:31:09"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"23/02/2026 16:20:42","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Seria qual curso senhora Elizabeth?","time":"23/02/2026 16:21:05","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Psicoteologia","time":"23/02/2026 16:22:54"},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n******************\nDisciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão\n*********\nO valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\nEsse mês esta com condições especiais com 50% de desconto e as mensalidades ficam por R$ 243,50\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, *previsto para 30/03.\n","time":"23/02/2026 16:26:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"24/02/2026 15:17:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Ficou alguma duvida?","time":"24/02/2026 15:17:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição?😊","time":"24/02/2026 15:17:31","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nElizabeth Brito, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"25/02/2026 18:10:35"}]$tag$, $tag$2026-02-23 15:26:58+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:42:01.563441+00$tag$, 9, 10, 10, 2, 9, 7, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9a6f488b-7972-4c04-8bbb-a36ae868cf90$tag$, $tag$2026022400046$tag$, $tag$Adenilson (5583987497059)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"24/02/2026 09:02:46"},{"role":"client","text":"🌟 Bom dia Adenilson! Que alegria ter você aqui com a gente! 🙌","time":"24/02/2026 09:02:47"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"24/02/2026 09:02:51"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"24/02/2026 09:02:55"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"24/02/2026 09:03:00"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"24/02/2026 09:03:06"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"24/02/2026 09:03:12"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"24/02/2026 09:03:12"},{"role":"client","text":"Sim, concordo","time":"24/02/2026 09:03:24"},{"role":"client","text":"✅ Obrigado, Adenilson! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"24/02/2026 09:03:25"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"24/02/2026 09:03:29"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"24/02/2026 09:04:30"},{"role":"client","text":"Olá! Adenilson!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"24/02/2026 09:04:31"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"24/02/2026 09:04:35"},{"role":"client","text":"Saber sobre os cursos","time":"24/02/2026 09:04:51"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"24/02/2026 09:04:55"},{"role":"client","text":"Graduação","time":"24/02/2026 09:05:57"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"24/02/2026 09:06:01"},{"role":"client","text":"Direito (Presencial)","time":"24/02/2026 09:06:33"},{"role":"client","text":"Excelente escolha! O curso de Direito da FICV é presencial em João Pessoa, tem nota máxima no MEC, prática jurídica desde o primeiro período e bolsa de 60% em todas as mensalidades!\n","time":"24/02/2026 09:06:34"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"24/02/2026 09:06:38"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"24/02/2026 09:07:04"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"24/02/2026 09:07:05"},{"role":"client","text":"Tenho três dúvidas: meu filho terminou pelo supletivo EJA agora no final de janeiro, então quero saber se pode entrar no curso com uma declaração de conclusão, pois o certificado demora 6 meses para emitir?","time":"24/02/2026 09:14:05"},{"role":"client","text":"Se ainda é possível entrar neste semestre?","time":"24/02/2026 09:14:26"},{"role":"client","text":"E se pode disponibilizar o quadro horário das aulas por dia da semana","time":"24/02/2026 09:15:01"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"24/02/2026 09:15:10"},{"role":"agent","text":"*Karina Pimentel:* Ele é maior de 18 anos?","time":"24/02/2026 09:17:49","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sim, fez agora em dezembro. Cursou a primeira metade do terceiro ano no interactivo, mas viemos para Portugal em julho então terminou pelo EJA-EAD","time":"24/02/2026 09:18:50"},{"role":"client","text":"Ele está voltando agora, mas estou em dúvida se ainda consegue cursar esse semestre após fazer a redação para ingressar","time":"24/02/2026 09:27:15"},{"role":"agent","text":"*Karina Pimentel:* Pode se ingressar sim!","time":"24/02/2026 09:40:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Se puder me manda o quadro horário para ver se ele consegue se adequar neste semestre","time":"24/02/2026 09:42:45"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"24/02/2026 09:44:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 ","time":"24/02/2026 09:45:39","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"A dele é para Direito","time":"24/02/2026 09:46:22"},{"role":"agent","text":"*Karina Pimentel:* Perdão!","time":"24/02/2026 09:47:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou enviar as informações corretas!","time":"24/02/2026 09:47:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.\n\n  Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"24/02/2026 09:47:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação!\n\nA primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"24/02/2026 09:49:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tem o quadro horário para ver se consegue acompanhar neste semestre","time":"24/02/2026 09:50:24"},{"role":"agent","text":"*Karina Pimentel:* De segunda à sexta, das 19h 