INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$00106688-fbfa-4812-9643-82fb1512548e$tag$, $tag$2026022300176$tag$, $tag$Rafaela Guerreiro (5519982033966)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"23/02/2026 15:36:11"},{"role":"client","text":"🌟 Boa tarde Rafaela Guerreiro! Que alegria ter você aqui com a gente! 🙌","time":"23/02/2026 15:36:12"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/02/2026 15:36:16"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/02/2026 15:36:20"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"23/02/2026 15:36:24"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"23/02/2026 15:36:30"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"23/02/2026 15:36:36"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"23/02/2026 15:36:37"},{"role":"client","text":"Sim, concordo","time":"23/02/2026 15:38:01"},{"role":"client","text":"✅ Obrigado, Rafaela Guerreiro! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"23/02/2026 15:38:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/02/2026 15:38:06"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/02/2026 15:41:26"},{"role":"client","text":"Olá! Rafaela Guerreiro!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/02/2026 15:41:27"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/02/2026 15:41:31"},{"role":"client","text":"Saber sobre os cursos","time":"23/02/2026 16:03:26"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/02/2026 16:03:31"},{"role":"client","text":"Pós-Graduação","time":"23/02/2026 16:06:44"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/02/2026 16:06:48"},{"role":"client","text":"Educação Cristã Clássica","time":"23/02/2026 16:13:45"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"23/02/2026 16:13:46"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/02/2026 16:13:49"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/02/2026 16:14:08"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/02/2026 16:14:09"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"23/02/2026 16:31:19"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"23/02/2026 16:31:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nAo pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"23/02/2026 16:31:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"23/02/2026 16:31:56","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Quando iniciará uma nova turma?","time":"24/02/2026 06:28:20"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"24/02/2026 08:08:45","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Abril e próxima em Setembro!","time":"24/02/2026 08:09:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"24/02/2026 15:22:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Ficou alguma duvida?","time":"24/02/2026 15:22:50","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição?","time":"24/02/2026 15:23:01","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Boa tarde! Para realizar a partir de setembro, como funciona?","time":"24/02/2026 15:26:16"},{"role":"agent","text":"*Karina Pimentel:* Ainda não estamos com links disponiveis para essa inscrição!","time":"24/02/2026 15:54:36","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* Somente em Julho!","time":"24/02/2026 15:54:53","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nRafaela Guerreiro, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"25/02/2026 18:11:49"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"25/02/2026 18:11:51"},{"role":"client","text":"Rafaela Guerreiro, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"25/02/2026 18:26:52"}]$tag$, $tag$2026-02-23 15:36:11+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
