INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$235dff7e-2afd-4cd7-911e-e432df1879c8$tag$, $tag$2026022300191$tag$, $tag$Daniela (5527998837965)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"23/02/2026 16:39:28"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"23/02/2026 16:39:29"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/02/2026 16:43:58"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"23/02/2026 16:44:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"23/02/2026 16:44:18","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"23/02/2026 16:44:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"23/02/2026 16:44:27","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"23/02/2026 16:44:34","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"24/02/2026 08:14:33","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nDaniela, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"24/02/2026 17:03:33"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"26/02/2026 16:37:31"},{"role":"client","text":"Sua sessão expirou!","time":"26/02/2026 16:39:33"}]$tag$, $tag$2026-02-23 16:39:28+00$tag$, FALSE, FALSE, 7.4, $tag$2026-03-01 16:42:01.563441+00$tag$, 9, 10, 7, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c49e07ff-1f16-464e-8ea2-34bb7ffcd31e$tag$, $tag$2026020900072$tag$, $tag$Tatiana Cocarelli Marmo (5564992217292)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"09/02/2026 09:14:11"},{"role":"client","text":"🌟 Bom dia Tatiana Cocarelli Marmo! Que alegria ter você aqui com a gente! 🙌","time":"09/02/2026 09:14:12"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/02/2026 09:14:16"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/02/2026 09:14:20"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"09/02/2026 09:14:24"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/02/2026 09:14:30"},{"role":"client","text":"Gostaria de fazer inscrição para a pós graduação nos cursos do Sayao","time":"09/02/2026 09:14:31"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/02/2026 09:14:32"},{"role":"client","text":"Por FABOR","time":"09/02/2026 09:14:33"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"09/02/2026 09:14:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/02/2026 09:14:35"},{"role":"client","text":"Sim, concordo","time":"09/02/2026 09:15:29"},{"role":"client","text":"✅ Obrigado, Tatiana Cocarelli Marmo! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"09/02/2026 09:15:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/02/2026 09:15:33"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/02/2026 09:15:49"},{"role":"client","text":"Olá! Tatiana Cocarelli Marmo!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/02/2026 09:15:50"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/02/2026 09:15:54"},{"role":"client","text":"Falar com um atendente","time":"09/02/2026 09:16:11"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"09/02/2026 09:16:12"},{"role":"client","text":"Quero me inscrever em pós graduação com Sayão","time":"09/02/2026 09:16:49"},{"role":"client","text":"Eu já vi feito a inscrição em novembro do ano passado, mas meu cartão deu parte doi feito o cancelamento e eu não tinha percebido","time":"09/02/2026 09:18:39"},{"role":"client","text":"Fui somente perceber agora","time":"09/02/2026 09:18:45"},{"role":"client","text":"E gostaria muito de fazer essa pós","time":"09/02/2026 09:18:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/02/2026 09:50:56"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n\n  *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\nTeologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações.\n\nO valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. ","time":"09/02/2026 09:51:32","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Correto","time":"09/02/2026 10:59:29"},{"role":"client","text":"Quero me inscrever","time":"09/02/2026 10:59:34"},{"role":"client","text":"Como faço o pagamento?","time":"09/02/2026 10:59:43"},{"role":"agent","text":"*Karina Pimentel:* 📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado","time":"09/02/2026 11:01:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6989e8f690a7469e6700400e)","time":"09/02/2026 11:02:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Eu no tenho o login e senha","time":"09/02/2026 11:07:19"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6989ec34b24af78a3b0c5930)","time":"09/02/2026 11:16:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"09/02/2026 11:16:52"},{"role":"client","text":"Uma dúvida","time":"09/02/2026 11:16:55"},{"role":"client","text":"Não tem polo em São Paulo?","time":"09/02/2026 11:17:03"},{"role":"client","text":"Atendimento Finalizado!\n\nTatiana Cocarelli Marmo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 09:43:22"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 09:43:23"},{"role":"client","text":"Tatiana Cocarelli Marmo, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 09:58:25"}]$tag$, $tag$2026-02-09 09:14:11+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 4, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
