INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$76807e41-c1f0-4256-8b9e-817dac8cb937$tag$, $tag$2026021000449$tag$, $tag$Tamiris (5519998895919)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi","time":"10/02/2026 14:07:42"},{"role":"client","text":"🌟 Boa tarde Tamiris! Que alegria ter você aqui com a gente! 🙌","time":"10/02/2026 14:07:42"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"10/02/2026 14:07:46"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"10/02/2026 14:07:50"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"10/02/2026 14:07:54"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"10/02/2026 14:08:00"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"10/02/2026 14:08:05"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"10/02/2026 14:08:06"},{"role":"client","text":"Sim, concordo","time":"10/02/2026 14:09:06"},{"role":"client","text":"✅ Obrigado, Tamiris! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"10/02/2026 14:09:07"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"10/02/2026 14:09:11"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"10/02/2026 14:09:33"},{"role":"client","text":"Olá! Tamiris!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"10/02/2026 14:09:34"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"10/02/2026 14:09:38"},{"role":"client","text":"Falar com um atendente","time":"10/02/2026 14:09:54"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"10/02/2026 14:09:55"},{"role":"client","text":"Pós graduação","time":"10/02/2026 14:10:57"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 10:12:27"},{"role":"client","text":"Oi","time":"11/02/2026 10:32:01"},{"role":"client","text":"Qual valor da pós de educação clássica?","time":"11/02/2026 10:32:02"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n","time":"11/02/2026 18:24:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nAo pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"11/02/2026 18:25:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"11/02/2026 18:25:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Eu vou professora de escola clássica","time":"11/02/2026 18:26:12"},{"role":"client","text":"Que usa já material cidade viva","time":"11/02/2026 18:26:18"},{"role":"client","text":"Quanto fica","time":"11/02/2026 18:27:05"},{"role":"client","text":"?","time":"11/02/2026 18:27:07"},{"role":"agent","text":"*Karina Pimentel:* Boa noite!","time":"11/02/2026 18:38:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Seria 50% de desconto!","time":"11/02/2026 18:38:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ah sim","time":"11/02/2026 18:38:47"},{"role":"client","text":"A escola me falou que era 80","time":"11/02/2026 18:40:47"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"12/02/2026 11:43:20","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Se for parceira com o Education sim! Precisamos apenas confirma a escola parceira!😉","time":"12/02/2026 11:43:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Aí ficaria qual valor","time":"12/02/2026 12:00:28"},{"role":"client","text":"?","time":"12/02/2026 12:00:29"},{"role":"client","text":"Escola logos","time":"12/02/2026 12:00:50"},{"role":"agent","text":"*Karina Pimentel:* Estou confirmando ok!","time":"12/02/2026 15:03:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Confirmado, 80% de desconto!\n","time":"12/02/2026 15:10:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"","time":"12/02/2026 15:11:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Poderia me falar o valor que fica com desconto","time":"12/02/2026 15:12:21"},{"role":"agent","text":"*Karina Pimentel:* R$ 95,83","time":"12/02/2026 15:13:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"13/02/2026 09:14:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deu certo a sua inscrição senhora Tamiris?","time":"13/02/2026 09:14:36","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Bom dia","time":"13/02/2026 13:58:29"},{"role":"client","text":"Ainda não fiz","time":"13/02/2026 13:58:32"},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estamos a disposição!","time":"13/02/2026 16:19:06","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/02/2026 13:56:34"},{"role":"client","text":"Sua sessão expirou!","time":"16/02/2026 13:58:36"}]$tag$, $tag$2026-02-10 14:07:42+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 14, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
