INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1586e7c7-e5b9-4b9a-aefe-88f00727819e$tag$, $tag$2026020900091$tag$, $tag$Fisio Alana Massena (5583999002951)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"09/02/2026 09:34:06"},{"role":"client","text":"🌟 Bom dia Fisio Alana Massena! Que alegria ter você aqui com a gente! 🙌","time":"09/02/2026 09:34:07"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/02/2026 09:34:11"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/02/2026 09:34:15"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/02/2026 09:34:22"},{"role":"client","text":"Gostaria de informações sobre o curso bacharel em.teologia ead","time":"09/02/2026 09:34:25"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"09/02/2026 09:34:26"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/02/2026 09:34:27"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/02/2026 09:34:32"},{"role":"client","text":"Olá! Fisio Alana Massena!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/02/2026 09:34:33"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/02/2026 09:34:37"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/02/2026 09:34:40"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"09/02/2026 09:34:41"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/02/2026 09:34:45"},{"role":"client","text":"Saber sobre os cursos","time":"09/02/2026 09:34:47"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/02/2026 09:34:51"},{"role":"client","text":"Saber sobre os cursos","time":"09/02/2026 09:34:55"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"09/02/2026 09:34:57"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/02/2026 09:35:00"},{"role":"client","text":"Graduação","time":"09/02/2026 09:35:01"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"09/02/2026 09:35:05"},{"role":"client","text":"Graduação","time":"09/02/2026 09:35:14"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"09/02/2026 09:35:15"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"09/02/2026 09:35:19"},{"role":"client","text":"Teologia (EAD)","time":"09/02/2026 09:35:31"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"09/02/2026 09:35:33"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/02/2026 09:35:37"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/02/2026 09:35:54"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"09/02/2026 09:35:55"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/02/2026 09:52:51"},{"role":"client","text":"Bom dia","time":"09/02/2026 09:53:17"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\n🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom BOLSA10\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38","time":"09/02/2026 09:53:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Não entendi sobre as mensalidades","time":"09/02/2026 09:54:56"},{"role":"client","text":"Eu já sou aluna da pós graduação ead","time":"09/02/2026 09:55:05"},{"role":"client","text":"Tem desconto a mais para alunos? 😊","time":"09/02/2026 09:55:21"},{"role":"client","text":"Qual o valor da mensalidade mensal com desconto?","time":"09/02/2026 09:55:45"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"09/02/2026 10:43:20","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Teria 20% de desconto!","time":"09/02/2026 10:43:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Oba","time":"09/02/2026 10:44:11"},{"role":"client","text":"Fica qt?","time":"09/02/2026 10:44:15"},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 383,71 por mês! 🎉 Usando o cupom BOLSA20\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"09/02/2026 10:49:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"383?","time":"09/02/2026 10:51:09"},{"role":"agent","text":"*Karina Pimentel:* Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56","time":"09/02/2026 10:56:08","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Realmente é meu sonho fazer, mas esse valor não tá dando no meu orçamento, já irei pagar a mensalidade da pós também","time":"09/02/2026 10:57:25"},{"role":"client","text":"Obrigada!","time":"09/02/2026 10:57:31"},{"role":"client","text":"Boa tarde","time":"10/02/2026 14:28:19"},{"role":"client","text":"Me tire uma dúvida","time":"10/02/2026 14:28:26"},{"role":"client","text":"A graduação EAD é o mesmo valor da graduação presencial?","time":"10/02/2026 14:28:59"},{"role":"agent","text":"*Karina Pimentel:* Oi, pode falar agora?","time":"12/02/2026 10:05:24","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Posso sim","time":"12/02/2026 10:13:56"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\n🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom BOLSA10\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n","time":"12/02/2026 13:45:13","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Teologia Presencial\n\nA nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC (*bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.\n\nSegue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\nA mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 30%* na pontualidade durante toda graduação, que fica apenas R$ 384,69.  *Usando o cupom de desconto: BOLSA30*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.308,15).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 461,63 = R$ 2.308,15\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 577,03 = R$ 2.308,15\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"12/02/2026 13:45:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"12/02/2026 15:26:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"12/02/2026 15:26:47","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nFisio Alana Massena, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 15:26:50"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 15:26:51"},{"role":"client","text":"Fisio Alana Massena, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 15:41:52"}]$tag$, $tag$2026-02-09 09:34:06+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
