INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$fc88fc81-b515-46b7-9ffe-bb05af9bd1b7$tag$, $tag$2026020900119$tag$, $tag$Vagner Molina (5511997583397)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Gostaria de conhecer o conteúdo programático da pós com o Luiz Sayão.","time":"09/02/2026 10:04:09"},{"role":"client","text":"🌟 Bom dia Vagner Molina! Que alegria ter você aqui com a gente! 🙌","time":"09/02/2026 10:04:10"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/02/2026 10:04:13"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/02/2026 10:04:17"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"09/02/2026 10:04:21"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/02/2026 10:04:27"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"09/02/2026 10:04:33"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/02/2026 10:04:33"},{"role":"client","text":"Ok. Concordo","time":"09/02/2026 10:07:47"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.","time":"09/02/2026 10:07:48"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/02/2026 10:07:48"},{"role":"client","text":"Sim, concordo","time":"09/02/2026 10:07:51"},{"role":"client","text":"✅ Obrigado, Vagner Molina! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"09/02/2026 10:07:52"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/02/2026 10:07:56"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/02/2026 10:13:02"},{"role":"client","text":"Olá! Vagner Molina!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/02/2026 10:13:03"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/02/2026 10:13:07"},{"role":"client","text":"Saber sobre os cursos","time":"09/02/2026 10:13:21"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/02/2026 10:13:26"},{"role":"client","text":"Pós-Graduação","time":"09/02/2026 10:13:40"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"09/02/2026 10:13:44"},{"role":"client","text":"Missiologia Urbana","time":"09/02/2026 10:14:12"},{"role":"client","text":"Aprenda a ler, servir e transformar as cidades com o Evangelho.\n 🏙️ Curso inovador com foco em missão no contexto urbano\n 🎯 Ideal para plantadores de igrejas, missionários e líderes urbanos\n 🕊️ Aulas online com mentoria prática\n","time":"09/02/2026 10:14:13"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/02/2026 10:14:17"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/02/2026 10:14:36"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"09/02/2026 10:14:37"},{"role":"client","text":"Ok…quero também conhecer a pós teologia do novo testamento.","time":"09/02/2026 10:15:28"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"09/02/2026 11:49:24"},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"09/02/2026 11:49:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"09/02/2026 11:49:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. \n\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"09/02/2026 11:49:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Por favor, pode me enviar também o programa de Missiologia Urbana?","time":"09/02/2026 12:07:14"},{"role":"client","text":"Quais são os professores que ministram nas duas pós?( teologia NT e Missiologia urbana)","time":"09/02/2026 12:08:24"},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698a0aa191b569e52c04fb98)","time":"09/02/2026 13:26:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698a0aa308635722f7034b06)","time":"09/02/2026 13:26:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Pós-Graduação em Missiologia Urbana*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"09/02/2026 13:26:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  *Missiologia Urbana* - Disciplinas do Curso:\n\nESPIRITUALIDADE MISSIONAL E CULTURA\n1 Teologia e Prática da Espiritualidade (Dr. Valdir Steuernagel e Dr. Tom White)\n2 Teologia da Missão Urbana (Dr. Sérgio Lyra e Dr. Mac Pier)\n3 Contextualização do Evangelho e da Cultura (Miss. Leandro Silva)\n\nMISSÃO E INTEGRALIDADE\n4 Missão Integral (Dr Chris Wright e Miss. Leandro Silva)\n5 Etnografia dos Grupos Urbanos (Dr Mark Matlock e Esp. Renildo Diniz)\n6 Eclesiologia Missional (Ms Valtenci Oliveira)\n\nMISSIONALIDADE, TRANSFORMAÇÃO E CIDADANIA\n7 Fé, Política e Cidadania (Davi Lago)\n8 Justiça, Pobreza e Transformação (Dr N. T. Wright e Ms Bebeto Araújo)\n9 Igreja e Meio-Ambiente (Esp. José Marcos da Silva)\n\nGESTÃO MISSIONAL\n10 Liderança Missional Urbana (Dr. Sérgio Queiroz)\n11 Captação de Recursos para Projetos Sociais (Ms Rafael Bandeira)\n12 Elaboração de Projetos Missionais Urbanos (Esp. Lisania Pereira)\n\nObs: Professores sujeitos a alterações. ","time":"09/02/2026 13:26:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Missiologia Urbana está em 16 mensalidades de *R$ 359,37*. \n\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para abril/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"09/02/2026 13:26:39","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Muito grato, Thayanne! Vou avaliar todas as informações, minha ideia e necessidade é começar em Junho/Julho pois até lá estarei concluindo a Faculdade Teológica.","time":"09/02/2026 16:23:09"},{"role":"agent","text":"*Thayanne Sales:* Você pode iniciar a sua pós que inicia em abril e você tem até o fim da pós para nos enviar o diploma da graduação.","time":"09/02/2026 17:37:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Interessante👍….vou levar em consideração isso, por sua vez terei custo duplo, verei se consigo pagar. Mais uma vez muito obrigado.","time":"09/02/2026 17:40:23"},{"role":"agent","text":"*Thayanne Sales:* Você paga a 1ª agora e as demais só em abril quando o curso iniciar","time":"09/02/2026 17:46:52","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* E para facilitar a sua escolha lhe dou 50% desconto em qualquer dos dois cursos. ","time":"09/02/2026 17:47:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* e as mensalidades  ficarão por apenas  R$ 179,68","time":"09/02/2026 17:47:50","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Excelente! Te dou o retorno em breve.","time":"09/02/2026 17:48:19"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e uma ótima semana","time":"09/02/2026 17:48:36","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Amém! Deus te abençoe ricamente vc e família.","time":"09/02/2026 17:49:16"},{"role":"client","text":"Atendimento Finalizado!\n\nVagner Molina, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"11/02/2026 08:06:05"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"11/02/2026 08:06:06"},{"role":"client","text":"Vagner Molina, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"11/02/2026 08:21:07"}]$tag$, $tag$2026-02-09 10:04:09+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 13, $tag$96