INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$17c3c5b4-34d4-4dc9-bf53-0657e1925b05$tag$, $tag$2026020900291$tag$, $tag$Ricardo de Andrade 😎🙏💒📖❤ (5511977990641)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"09/02/2026 14:09:56"},{"role":"client","text":"🌟 Boa tarde Ricardo de Andrade 😎🙏💒📖❤! Que alegria ter você aqui com a gente! 🙌","time":"09/02/2026 14:09:57"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/02/2026 14:10:01"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/02/2026 14:10:05"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"09/02/2026 14:10:10"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/02/2026 14:10:16"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"09/02/2026 14:10:21"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/02/2026 14:10:22"},{"role":"client","text":"Sim, concordo","time":"09/02/2026 14:10:48"},{"role":"client","text":"✅ Obrigado, Ricardo de Andrade 😎🙏💒📖❤! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"09/02/2026 14:10:49"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/02/2026 14:10:54"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/02/2026 14:12:06"},{"role":"client","text":"Olá! Ricardo de Andrade 😎🙏💒📖❤!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/02/2026 14:12:07"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/02/2026 14:12:11"},{"role":"client","text":"Saber sobre os cursos","time":"09/02/2026 14:15:37"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/02/2026 14:15:41"},{"role":"client","text":"Graduação","time":"09/02/2026 14:18:29"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"09/02/2026 14:18:33"},{"role":"client","text":"Teologia (EAD)","time":"09/02/2026 14:18:48"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"09/02/2026 14:18:49"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/02/2026 14:18:53"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/02/2026 14:19:12"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"09/02/2026 14:19:13"},{"role":"client","text":"Ok","time":"09/02/2026 14:19:57"},{"role":"client","text":"❓","time":"09/02/2026 14:43:27"},{"role":"client","text":"Boa tarde","time":"09/02/2026 17:05:23"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/02/2026 19:51:15"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"10/02/2026 08:44:21"},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"10/02/2026 08:44:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"10/02/2026 08:44:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 479,64/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 431,67 por mês!\n\n✨ Primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas. \n\n(Lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. )\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"10/02/2026 08:44:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"10/02/2026 08:44:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nRicardo de Andrade 😎🙏💒📖❤, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"10/02/2026 17:28:52"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"10/02/2026 17:28:53"},{"role":"client","text":"Ricardo de Andrade 😎🙏💒📖❤, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"10/02/2026 17:43:55"}]$tag$, $tag$2026-02-09 14:09:56+00$tag$, FALSE, FALSE,