INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$7ff1d092-7fca-4aac-93d4-93907f608c74$tag$, $tag$2026020900149$tag$, $tag$Wisley Oliveira (5531986281686)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"09/02/2026 10:34:10"},{"role":"client","text":"🌟 Bom dia Wisley Oliveira! Que alegria ter você aqui com a gente! 🙌","time":"09/02/2026 10:34:11"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/02/2026 10:34:15"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/02/2026 10:34:19"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"09/02/2026 10:34:23"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/02/2026 10:34:29"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"09/02/2026 10:34:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/02/2026 10:34:35"},{"role":"client","text":"Sim, concordo","time":"09/02/2026 10:34:57"},{"role":"client","text":"✅ Obrigado, Wisley Oliveira! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"09/02/2026 10:34:58"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/02/2026 10:35:02"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/02/2026 10:35:19"},{"role":"client","text":"Olá! Wisley Oliveira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/02/2026 10:35:21"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/02/2026 10:35:25"},{"role":"client","text":"Saber sobre os cursos","time":"09/02/2026 10:37:43"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/02/2026 10:37:47"},{"role":"client","text":"Pós-Graduação","time":"09/02/2026 10:38:25"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"09/02/2026 10:38:29"},{"role":"client","text":"Psicoteologia","time":"09/02/2026 10:38:56"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"09/02/2026 10:38:58"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/02/2026 10:39:02"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/02/2026 10:40:19"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"09/02/2026 10:40:20"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/02/2026 11:46:11"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\n🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom BOLSA10\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"09/02/2026 11:46:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tenho dúvidas a respeito da Pós em Psicologia","time":"09/02/2026 11:50:37"},{"role":"agent","text":"*Karina Pimentel:* Seria Psicoteologia?","time":"09/02/2026 11:53:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Ou Psicopedagogia?","time":"09/02/2026 11:53:19","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Psicoteologia","time":"09/02/2026 12:04:16"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"09/02/2026 13:36:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar as informações!","time":"09/02/2026 13:36:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"As aulas são gravadas ou ao vivo?","time":"09/02/2026 13:37:16"},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n******************\nDisciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão\n*********\nO valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\nEsse mês esta com condições especiais com 50% de desconto e as mensalidades ficam por R$ 243,50\n\nAo pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, *previsto para Fevereiro 2026*!\n","time":"09/02/2026 13:37:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nWisley Oliveira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 09:52:07"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 09:52:09"},{"role":"client","text":"Wisley Oliveira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 10:07:10"}]$tag$, $tag$2026-02-09 10:34:10+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 6, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
